"""Reusable bounded vector-field and scalar-potential diagram renderer."""
from physics_playground.canvas.player import build_player_document
SCENE=r"""
const scene={draw(ctx,s){const w=s.transform.width,h=s.transform.height,c=s.config.vectorField||{},n=c.gridSize||1,items=c.samples||[],X=x=>(x+c.extent)/(2*c.extent)*w,Y=y=>h-(y+c.extent)/(2*c.extent)*h;PhysicsVisuals.background(ctx,s);const finite=items.filter(p=>p.v!==null),limit=Math.max(1,...finite.map(p=>Math.abs(p.v)));for(const p of finite){const t=Math.max(-1,Math.min(1,p.v/limit)),red=t>0?220:40,blue=t<0?220:40;ctx.fillStyle=`rgba(${red},120,${blue},.18)`;ctx.fillRect(X(p.x)-w/n/2,Y(p.y)-h/n/2,w/n+1,h/n+1)}for(let i=1;i<items.length;i++){const a=items[i-1],b=items[i];if(a.v!==null&&b.v!==null&&Math.floor((a.v/limit)*8)!==Math.floor((b.v/limit)*8)){ctx.strokeStyle='rgba(80,80,80,.28)';ctx.strokeRect(X(b.x)-w/n/2,Y(b.y)-h/n/2,w/n,h/n)}}const visible=Math.max(.05,s.fraction);for(const p of finite){const mag=Math.hypot(p.ex,p.ey);if(!mag)continue;const len=(5+13*Math.min(1,Math.log10(1+mag)/6))*visible,dx=p.ex/mag*len,dy=-p.ey/mag*len,x=X(p.x),y=Y(p.y);PhysicsVisuals.arrow(ctx,s,{x:x-dx*.35,y:y-dy*.35},{x:x+dx*.65,y:y+dy*.65},{role:'electric_field',width:1.4,head:5})}for(const q of c.charges){PhysicsAssets.charge(ctx,s,{x:X(q.x),y:Y(q.y),radius:11,sign:q.q,shadow:false})}ctx.fillStyle=PhysicsVisuals.token(s,'colors','selected','#7C3AED');ctx.beginPath();ctx.arc(X(c.testX),Y(c.testY),6,0,Math.PI*2);ctx.fill();PhysicsAnnotations.disclosure(ctx,s,'normalized','Field directions are physical; arrow lengths are normalized for visibility',12,12);}};
"""
def build_vector_field_document(*,samples:list[dict],charges:list[dict],grid_size:int,extent:float,test_x:float,test_y:float,message:str,seed:int)->str:
    config={"durationMs":1600,"autoplay":False,"seed":seed,"tracks":[{"id":"field-reveal","label":"Electric field reveal","x":[0,1]}],"events":[],"completionMessage":message,"vectorField":{"samples":samples,"charges":charges,"gridSize":grid_size,"extent":extent,"testX":test_x,"testY":test_y},"view":{"minimum":0,"maximum":1}}
    return build_player_document(config=config,scene_javascript=SCENE,logical_width=760,logical_height=620,accessible_label="Electric-field vectors and equipotential bands. "+message,idle_hint="Press Play to reveal field vectors")
